from Crypto.Util.number import *
from flags import flag1 as flag

def gen_special():
    while True:
        cur = 2
        for i in range(30):
            cur *= getPrime(20)
        if isPrime(cur+1):
            return cur+1

p, q = gen_special(), gen_special()
N = p * q
e = 0x10001
c = pow(bytes_to_long(flag) ,e , N)
print(f"{N=}\n{e=}\n{c=}")

